-- Convert the "Intensive Listening Advanced N" lessons (N = 1..13) in
-- "The Canto to Mando Blueprint - Advanced" from Audio to Listening Practice,
-- keeping titles and loading the Mandarin sentences from the Advanced doc.
-- Pinyin = the doc's (typos/wrong-chars/glued-syllables corrected, cleaned to
-- one syllable per character); English = translations; audio = per-sentence TTS.
--
-- Idempotent + scoped: only lessons still typed 'audio', titled
-- "Intensive Listening…", in that course, matched to content by title number.

UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = v.content,
    "updated_at" = now()
FROM (VALUES
  (1, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"7d243c1d-9557-448d-a447-92c4e6b49cd2","order":0,"chinese":"我应该可以习惯北方的天气","pinyin":"wǒ yīng gāi kě yǐ xí guàn běi fāng de tiān qì","english":"I should be able to get used to the weather in the north","audioUrl":null},{"id":"d33f37c6-603b-4173-ab04-c5f10b7f218e","order":1,"chinese":"我可以跟你去踢足球","pinyin":"wǒ kě yǐ gēn nǐ qù tī zú qiú","english":"I can go play soccer with you","audioUrl":null},{"id":"bd3e3e7f-4688-4887-94ae-2a233c0e9f66","order":2,"chinese":"我会讲普通话","pinyin":"wǒ huì jiǎng pǔ tōng huà","english":"I can speak Mandarin","audioUrl":null},{"id":"c3f47ff6-6bf6-4833-87cc-adca014d7a89","order":3,"chinese":"我不会解释这个问题","pinyin":"wǒ bú huì jiě shì zhè ge wèn tí","english":"I don''t know how to explain this problem","audioUrl":null},{"id":"becaeb9a-9209-445c-b5c0-2b051b52c1ce","order":4,"chinese":"我不能刷牙","pinyin":"wǒ bú néng shuā yá","english":"I can''t brush my teeth","audioUrl":null},{"id":"ea1dcb66-4607-428b-a1ac-c9a67964c8ee","order":5,"chinese":"这个方法不行","pinyin":"zhè ge fāng fǎ bù xíng","english":"This method won''t work","audioUrl":null},{"id":"21ccaa57-6635-4830-9104-a6d88c5e9a84","order":6,"chinese":"我们可不可以去黄河游泳?","pinyin":"wǒ men kě bù kě yǐ qù huáng hé yóu yǒng","english":"Can we go swimming in the Yellow River?","audioUrl":null},{"id":"9b33da4b-76cc-42d5-8ffd-87ffdcc7d957","order":7,"chinese":"我的脚断了, 我不能跳舞","pinyin":"wǒ de jiǎo duàn le wǒ bù néng tiào wǔ","english":"My leg is broken, I can''t dance","audioUrl":null},{"id":"66cd52ad-fe7d-4eac-9ace-dcee2573bd50","order":8,"chinese":"你在家自己剪头发就行","pinyin":"nǐ zài jiā zì jǐ jiǎn tóu fa jiù xíng","english":"You can just cut your hair yourself at home","audioUrl":null},{"id":"8261b4e3-1d38-4036-8d98-997d75890028","order":9,"chinese":"妈妈很关心我, 因为我不会开车","pinyin":"mā ma hěn guān xīn wǒ yīn wèi wǒ bú huì kāi chē","english":"My mom worries about me a lot because I can''t drive","audioUrl":null}]}'::jsonb),
  (2, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"274f490b-22b7-478d-8c06-18a3f12dc9c1","order":0,"chinese":"我昨天晚上十点才到朋友家","pinyin":"wǒ zuó tiān wǎn shang shí diǎn cái dào péng yǒu jiā","english":"I didn''t get to my friend''s place until ten last night","audioUrl":null},{"id":"000abfb1-584e-437f-8812-5ff52fc1b208","order":1,"chinese":"他六十五岁才结婚!","pinyin":"tā liù shí wǔ suì cái jié hūn","english":"He didn''t get married until he was sixty-five!","audioUrl":null},{"id":"c563b5ae-b6cc-4c2a-82a6-e9370e875bb9","order":2,"chinese":"我刚刚才开车! 耐心一点吧!","pinyin":"wǒ gāng gang cái kāi chē nài xīn yì diǎn ba","english":"I just started driving! Be a little patient!","audioUrl":null},{"id":"07391790-7762-425b-85cb-d911f31c4e97","order":3,"chinese":"我刚才开车! 耐心一点吧!","pinyin":"wǒ gāng cái kāi chē nài xīn yì diǎn ba","english":"I was just driving! Be a little patient!","audioUrl":null},{"id":"7cb383a5-cff0-4010-a655-2044cbbd9983","order":4,"chinese":"你一定要喝牛奶才可以长高","pinyin":"nǐ yí dìng yào hē niú nǎi cái kě yǐ zhǎng gāo","english":"You have to drink milk in order to grow tall","audioUrl":null},{"id":"b229a2e3-b7bf-4627-8bb8-422b51dece7d","order":5,"chinese":"只有大家一起合作才可以成功","pinyin":"zhǐ yǒu dà jiā yì qǐ hé zuò cái kě yǐ chéng gōng","english":"Only if everyone works together can we succeed","audioUrl":null},{"id":"9afef37e-07b4-4c52-8ecf-ddc872035d02","order":6,"chinese":"其实你才是天才","pinyin":"qí shí nǐ cái shì tiān cái","english":"Actually, you''re the real genius","audioUrl":null},{"id":"b2e4a81a-cd62-41a8-a172-55e40f64abf5","order":7,"chinese":"但是人才才是最重要的","pinyin":"dàn shì rén cái cái shì zuì zhòng yào de","english":"But talented people are what matter most","audioUrl":null},{"id":"a394c127-c3bc-4cd7-bbce-61371b861842","order":8,"chinese":"你是今天早上出发的! 你现在才到公园吗?","pinyin":"nǐ shì jīn tiān zǎo shang chū fā de nǐ xiàn zài cái dào gōng yuán ma","english":"You left this morning! You''re only getting to the park now?","audioUrl":null},{"id":"27470c2d-6bf7-4b65-baef-1584660702a7","order":9,"chinese":"他昨天晚上十点才做完功课! 所以今天他不精神!","pinyin":"tā zuó tiān wǎn shang shí diǎn cái zuò wán gōng kè suǒ yǐ jīn tiān tā bù jīng shen","english":"He didn''t finish his homework until ten last night, so he''s not alert today!","audioUrl":null},{"id":"b80e1448-b933-4ebd-ba42-3e77481d60fb","order":10,"chinese":"只有你每天吃一个苹果, 你的身体才会健康","pinyin":"zhǐ yǒu nǐ měi tiān chī yí gè píng guǒ nǐ de shēn tǐ cái huì jiàn kāng","english":"Only if you eat an apple every day will your body stay healthy","audioUrl":null}]}'::jsonb),
  (3, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"64b2a00d-ae43-4527-8cb0-67db67d3fa62","order":0,"chinese":"我们必须欢迎客人才能让他们开心","pinyin":"wǒ mén bì xū huān yíng kè rén cái néng ràng tā mén kāi xīn","english":"We have to welcome the guests to make them happy","audioUrl":null},{"id":"de1355c2-4b99-420e-9657-eeca6aedf856","order":1,"chinese":"校长不让我去美国留学","pinyin":"xiào zhǎng bú ràng wǒ qù měi guó liú xué","english":"The principal won''t let me study abroad in America","audioUrl":null},{"id":"d61ac7f2-d8ad-40d7-860b-aac5168c4372","order":2,"chinese":"吹空调会让人容易困吗?","pinyin":"chuī kōng tiáo huì ràng rén róng yì kùn ma","english":"Does the air conditioning make people sleepy easily?","audioUrl":null},{"id":"b9bdf238-52b1-4572-ae8e-73d43f665bc7","order":3,"chinese":"除了让你瘦, 我想不到其它好处","pinyin":"chú le ràng nǐ shòu wǒ xiǎng bú dào qí tā hǎo chù","english":"Other than making you thin, I can''t think of any other benefit","audioUrl":null},{"id":"6f39112b-787a-480e-9a25-be3309fc23ba","order":4,"chinese":"老板说会议结束之后他会让我早点回家","pinyin":"lǎo bǎn shuō huì yì jié shù zhī hòu tā huì ràng wǒ zǎo diǎn huí jiā","english":"The boss said that after the meeting he''ll let me go home early","audioUrl":null},{"id":"4f822d79-55ee-494e-83ca-3f98ce608e04","order":5,"chinese":"让我帮你提高你的生活水平!","pinyin":"ràng wǒ bāng nǐ tí gāo nǐ de shēng huó shuǐ píng","english":"Let me help you improve your standard of living!","audioUrl":null},{"id":"6d97c601-e9ef-43b1-af84-d3ca8d7fe226","order":6,"chinese":"父母要求让孩子在网上上课","pinyin":"fù mǔ yāo qiú ràng hái zǐ zài wǎng shàng shàng kè","english":"The parents are asking for their kids to take classes online","audioUrl":null},{"id":"b82212b7-0511-40c5-beac-a6e9088bf1c8","order":7,"chinese":"怎么样才能让每个孩子对健康感兴趣","pinyin":"zěn me yàng cái néng ràng měi gè hái zǐ duì jiàn kāng gǎn xìng qù","english":"How can we get every child interested in health?","audioUrl":null},{"id":"e8eb7244-96ef-4c5e-b52c-23a486e9be24","order":8,"chinese":"可以给我买一杯咖啡吗?","pinyin":"kě yǐ gěi wǒ mǎi yì bēi kā fēi ma","english":"Can you buy me a cup of coffee?","audioUrl":null},{"id":"e84374c4-3cb5-43ba-af1b-da4010034a1f","order":9,"chinese":"给我拿桌子上的勺子, 刀子, 和叉子进厨房","pinyin":"gěi wǒ ná zhuō zǐ shàng de sháo zi dāo zi hé chā zi jìn chú fáng","english":"Bring me the spoon, knife, and fork on the table into the kitchen","audioUrl":null},{"id":"015e277a-0626-4282-9ff8-6802407a6c3f","order":10,"chinese":"你可以给我解释吗?","pinyin":"nǐ kě yǐ gěi wǒ jiě shì ma","english":"Can you explain it to me?","audioUrl":null},{"id":"a149a368-b3d0-4de5-acc9-246ed08ef0f0","order":11,"chinese":"你这样浪费钱会让你父母不开心","pinyin":"nǐ zhè yàng làng fèi qián huì ràng nǐ fù mǔ bù kāi xīn","english":"Wasting money like this will make your parents unhappy","audioUrl":null},{"id":"557a8446-ce63-4b42-a59f-46fc4e53e8d0","order":12,"chinese":"老师不让你出去是因为你不停做坏事","pinyin":"lǎo shī bú ràng nǐ chū qù shì yīn wèi nǐ bù tíng zuò huài shì","english":"The teacher won''t let you go out because you keep doing bad things","audioUrl":null},{"id":"2c75b7a4-7fb0-496e-9767-caf66c7386c6","order":13,"chinese":"我的成绩太差了! 我让我父母失望了","pinyin":"wǒ de chéng jī tài chà le wǒ ràng wǒ fù mǔ shī wàng le","english":"My grades are too bad! I''ve let my parents down","audioUrl":null}]}'::jsonb),
  (4, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"eb723f2e-cbd2-43ab-ba7d-d64600acb544","order":0,"chinese":"把那本书放在桌子上","pinyin":"bǎ nà běn shū fàng zài zhuō zi shàng","english":"Put that book on the table","audioUrl":null},{"id":"00676938-5b79-4e5b-b4f3-fddbda63ece9","order":1,"chinese":"白色桌子","pinyin":"bái sè zhuō zi","english":"A white table","audioUrl":null},{"id":"48a38120-a912-4086-b387-26f8b93510bb","order":2,"chinese":"我把苹果吃完了","pinyin":"wǒ bǎ píng guǒ chī wán le","english":"I finished eating the apple","audioUrl":null},{"id":"aacea562-0cd5-4f59-a3d4-d49dca47da9e","order":3,"chinese":"阿姨把最后两块蛋糕吃完了","pinyin":"ā yí bǎ zuì hòu liǎng kuài dàn gāo chī wán le","english":"Auntie finished the last two pieces of cake","audioUrl":null},{"id":"7b890f20-dff3-478f-8030-a64609cf45bd","order":4,"chinese":"记得把你的房间收拾干净","pinyin":"jì dé bǎ nǐ de fáng jiān shōu shí gān jìng","english":"Remember to tidy up your room","audioUrl":null},{"id":"0c490996-11d9-4d1b-bcf0-93d95d90e726","order":5,"chinese":"收拾你的房间","pinyin":"shōu shí nǐ de fáng jiān","english":"Clean your room","audioUrl":null},{"id":"067b1486-f4c9-45ee-9aa7-03c50fb20529","order":6,"chinese":"收拾你的东西","pinyin":"shōu shí nǐ de dōng xi","english":"Clean up your things","audioUrl":null},{"id":"0a9b423e-2493-4313-a889-5d7e5c8055b4","order":7,"chinese":"你们必须把办公室打扫干净","pinyin":"nǐ mén bì xū bǎ bàn gōng shì dǎ sǎo gān jìng","english":"You have to clean the office","audioUrl":null},{"id":"474027cc-81f9-4cf6-bf21-fff34fdd48ba","order":8,"chinese":"不要 把钱借给那个人","pinyin":"bú yào bǎ qián jiè gěi nà ge rén","english":"Don''t lend money to that guy","audioUrl":null},{"id":"ac1ae8dd-d515-4e5a-8c16-bd007fdf3d67","order":9,"chinese":"我没有把你照顾好","pinyin":"wǒ méi yǒu bǎ nǐ zhào gù hǎo","english":"I didn''t take good care of you","audioUrl":null},{"id":"fa27926f-0de1-47fa-89a1-4345481920bc","order":10,"chinese":"你可不可以把这个问题解释清楚一点","pinyin":"nǐ kě bù kě yǐ bǎ zhè gè wèn tí jiě shì qīng chǔ yì diǎn","english":"Could you explain this question a bit more clearly?","audioUrl":null},{"id":"8daadc7d-fdd1-402b-96a1-9dbfc23b2cdb","order":11,"chinese":"后来我终于把你忘记了","pinyin":"hòu lái wǒ zhōng yú bǎ nǐ wàng jì le","english":"In the end, I finally forgot you","audioUrl":null},{"id":"14554e7b-9f1f-47a1-bb18-6b9c05666f5c","order":12,"chinese":"我怎么可以把那首歌唱得好一点","pinyin":"wǒ zěn me kě yǐ bǎ nà shǒu gē chàng dé hǎo yì diǎn","english":"How can I sing that song a little better?","audioUrl":null},{"id":"ecfb2c36-7967-409a-ba00-d9d89c515e96","order":13,"chinese":"为什么男人都习惯把手表戴在左手","pinyin":"wèi shén me nán rén dōu xí guàn bǎ shǒu biǎo dài zài zuǒ shǒu","english":"Why do men usually wear their watch on the left hand?","audioUrl":null},{"id":"8e1ce8de-d00d-43fd-83f9-239e8cd35654","order":14,"chinese":"阿姨已经把蓝色的皮鞋送给我了","pinyin":"ā yí yǐ jīng bǎ lán sè de pí xié sòng gěi wǒ le","english":"Auntie already gave me the blue leather shoes","audioUrl":null}]}'::jsonb),
  (5, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"fe572a6d-8333-47e8-9812-548a460ac6a2","order":0,"chinese":"我家离公司很远","pinyin":"wǒ jiā lí gōng sī hěn yuǎn","english":"My home is far from the office","audioUrl":null},{"id":"4f97f0b1-1f36-4ed9-b1bb-2f0c63075e47","order":1,"chinese":"那个宾馆离火车站很近","pinyin":"nà gè bīn guǎn lí huǒ chē zhàn hěn jìn","english":"That hotel is close to the train station","audioUrl":null},{"id":"6c1088d5-8162-4570-88b1-4eee7465dd0d","order":2,"chinese":"洗手间离教室挺远的","pinyin":"xǐ shǒu jiān lí jiào shì tǐng yuǎn de","english":"The bathroom is pretty far from the classroom","audioUrl":null},{"id":"5a632b2f-64cd-45eb-9a95-0397bcee1de5","order":3,"chinese":"这个挺好的","pinyin":"zhè gè tǐng hǎo de","english":"This is pretty good","audioUrl":null},{"id":"3a02788f-5a05-4102-8a63-141118bbb7bc","order":4,"chinese":"这个蛮好的","pinyin":"zhè gè mán hǎo de","english":"This is quite good","audioUrl":null},{"id":"9cd74b32-0736-4d04-b98f-b887bccf5044","order":5,"chinese":"他家不是挺有钱的吗","pinyin":"tā jiā bú shì tǐng yǒu qián de ma","english":"Isn''t his family pretty rich?","audioUrl":null},{"id":"611f9043-aa6f-4059-be74-ef4463e7dcbe","order":6,"chinese":"他们是从学校出发的","pinyin":"tā men shì cóng xué xiào chū fā de","english":"They set off from the school","audioUrl":null},{"id":"817d062b-15e4-4ecf-b576-3f7423668e20","order":7,"chinese":"从今天到明天我想请假","pinyin":"cóng jīn tiān dào míng tiān wǒ xiǎng qǐng jiǎ","english":"I''d like to take leave from today until tomorrow","audioUrl":null},{"id":"5203a9e9-c535-4f5e-a349-74b20b769030","order":8,"chinese":"你不能从周一到周末不说话","pinyin":"nǐ bù néng cóng zhōu yī dào zhōu mò bù shuō huà","english":"You can''t go from Monday to the weekend without speaking","audioUrl":null},{"id":"d762125b-7205-48f3-a9c4-cbe445725010","order":9,"chinese":"你为什么不说话","pinyin":"nǐ wèi shén me bù shuō huà","english":"Why aren''t you speaking?","audioUrl":null},{"id":"6543eeba-82b6-473f-8c3f-6082f9afd8ae","order":10,"chinese":"往前走 400 米就到广场了","pinyin":"wǎng qián zǒu mǐ jiù dào guǎng chǎng le","english":"Walk forward 400 meters and you''ll reach the square","audioUrl":null},{"id":"3ddc65f0-671b-4d64-b58c-ea13e67c90ca","order":11,"chinese":"我们好像要往北走","pinyin":"wǒ men hǎo xiàng yào wǎng běi zǒu","english":"It seems we need to head north","audioUrl":null},{"id":"fd4a7967-b94b-4dbb-88aa-8ad1eebe0802","order":12,"chinese":"我希望这只鸟会一直往前飞","pinyin":"wǒ xī wàng zhè zhī niǎo huì yī zhí wǎng qián fēi","english":"I hope this bird will keep flying forward","audioUrl":null},{"id":"0042e459-604f-47f5-b05d-87468c83674c","order":13,"chinese":"从法国开车到德国一共要几个小时","pinyin":"cóng fǎ guó kāi chē dào dé guó yī gòng yào jǐ gè xiǎo shí","english":"How many hours does it take in total to drive from France to Germany?","audioUrl":null},{"id":"74219975-4891-428f-ae51-842eab1c4633","order":14,"chinese":"健身房离地铁站一万米","pinyin":"jiàn shēn fáng lí dì tiě zhàn yī wàn mǐ","english":"The gym is ten thousand meters from the subway station","audioUrl":null},{"id":"c48b24cb-3f7f-47d1-9f92-df3731ce9ac9","order":15,"chinese":"开车遇到这些标志的时候记得向左转","pinyin":"kāi chē yù dào zhè xiē biāo zhì de shí hòu jì dé xiàng zuǒ zhuǎn","english":"When you see these signs while driving, remember to turn left","audioUrl":null}]}'::jsonb),
  (6, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"176ee476-4a18-4b80-8c37-989bf7128745","order":0,"chinese":"我当然知道中国的历史很悠久","pinyin":"wǒ dāng rán zhī dào zhōng guó de lì shǐ hěn yōu jiǔ","english":"Of course I know that China has a long history","audioUrl":null},{"id":"60c489b1-8c8f-4ba6-9044-a96a3b311833","order":1,"chinese":"有哪些越早知道越好的人生经验?","pinyin":"yǒu nǎ xiē yuè zǎo zhī dào yuè hǎo de rén shēng jīng yàn","english":"What life lessons are better to learn as early as possible?","audioUrl":null},{"id":"f85b164f-da31-46df-9686-27a49ade4679","order":2,"chinese":"怎样知道自己的身体健不健康","pinyin":"zěn yàng zhī dào zì jǐ de shēn tǐ jiàn bu jiàn kāng","english":"How do you know whether your body is healthy or not?","audioUrl":null},{"id":"847e480a-710d-4e3a-b1dc-9b5262927b3b","order":3,"chinese":"其实我知道刮风天气对钓鱼的影响挺大","pinyin":"qí shí wǒ zhī dào guā fēng tiān qì duì diào yú de yǐng xiǎng tǐng dà","english":"Actually, I know that windy weather has quite a big effect on fishing","audioUrl":null},{"id":"d71b5bec-a05b-4745-92ad-af2f84a2e91d","order":4,"chinese":"我完全听不懂老师在说什么","pinyin":"wǒ wán quán tīng bù dǒng lǎo shī zài shuō shén me","english":"I can''t understand at all what the teacher is saying","audioUrl":null},{"id":"849885b2-7892-41e7-9e96-55c4bd934381","order":5,"chinese":"这几个坏习惯会让你看不懂中文词典","pinyin":"zhè jǐ gè huài xí guàn huì ràng nǐ kàn bù dǒng zhōng wén cí diǎn","english":"These few bad habits will keep you from being able to read a Chinese dictionary","audioUrl":null},{"id":"52fae7e7-7825-4dd7-aba6-b9e16b0446a3","order":6,"chinese":"我上网课一点都听不懂 - 我该怎么办?","pinyin":"wǒ shàng wǎng kè yì diǎn dōu tīng bù dǒng wǒ gāi zěn me bàn","english":"I don''t understand my online class at all — what should I do?","audioUrl":null},{"id":"89e807b6-cdeb-40f4-b426-b53b4b88047e","order":7,"chinese":"儿子明白他一定要有一个复习计划和目标","pinyin":"ér zǐ míng bái tā yí dìng yào yǒu yí gè fù xí jì huá hé mù biāo","english":"The son understands he must have a study plan and a goal","audioUrl":null},{"id":"96699efa-f481-4ae2-8254-9a545ec1a0dd","order":8,"chinese":"我不明白太阳和月亮有什么关系","pinyin":"wǒ bù míng bái tài yáng hé yuè liàng yǒu shén me guān xì","english":"I don''t understand what the sun and the moon have to do with each other","audioUrl":null},{"id":"5633dc41-7f8f-4212-bad6-b997e641febd","order":9,"chinese":"看来你还不明白丈夫的决定","pinyin":"kàn lái nǐ hái bù míng bái zhàng fū de jué dìng","english":"It seems you still don''t understand your husband''s decision","audioUrl":null},{"id":"759781db-f3cf-4c83-8b56-11d59832d1db","order":10,"chinese":"一个了解你的人, 不会一直让你难过","pinyin":"yí gè liǎo jiě nǐ de rén bú huì yī zhí ràng nǐ nán guò","english":"Someone who understands you won''t keep making you sad","audioUrl":null},{"id":"a8193567-aff6-4f61-a5e2-6d943f645b32","order":11,"chinese":"我打算了解一下骑自行车的交通规则","pinyin":"wǒ dǎ zuàn liǎo jiě yí xià qí zì xíng chē de jiāo tōng guī zé","english":"I plan to look into the traffic rules for riding a bicycle","audioUrl":null},{"id":"f009395b-9792-45c6-b163-dad4e65982ed","order":12,"chinese":"做选择之前, 你一定要认真了解一下这些事情!","pinyin":"zuò xuǎn zé zhī qián nǐ yí dìng yào rèn zhēn liǎo jiě yí xià zhè xiē shì qíng","english":"Before you make a choice, you must seriously look into these things!","audioUrl":null},{"id":"91673cc4-2e84-4965-920a-eb8adcfc02ad","order":13,"chinese":"虽然我认识你但是我忘了你的名字","pinyin":"suī rán wǒ rèn shi nǐ dàn shì wǒ wàng le nǐ de míng zi","english":"Even though I know you, I''ve forgotten your name","audioUrl":null},{"id":"413cf3c5-bff7-4c78-b0cc-1786e335ee27","order":14,"chinese":"我不懂为什么我的女朋友不满意","pinyin":"wǒ bù dǒng wèi shén me wǒ de nǚ péng yǒu bù mǎn yì","english":"I don''t get why my girlfriend isn''t satisfied","audioUrl":null},{"id":"4ed9d602-23b2-4d75-99b4-51de7fa85f04","order":15,"chinese":"你要明白这个世界有多危险","pinyin":"nǐ yào míng bái zhè gè shì jiè yǒu duō wēi xiǎn","english":"You need to understand how dangerous this world is","audioUrl":null},{"id":"257d5592-ae76-496c-8201-71180e2e3ca4","order":16,"chinese":"起飞之前, 旅客需要了解什么?","pinyin":"qǐ fēi zhī qián lǚ kè xū yào liǎo jiě shén me","english":"Before takeoff, what do passengers need to know?","audioUrl":null}]}'::jsonb),
  (7, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"21678074-7aa3-4e67-8e27-27568a9c1a32","order":0,"chinese":"我老婆总是早上去买菜","pinyin":"wǒ lǎo pó zǒng shì zǎo shàng qù mǎi cài","english":"My wife always goes grocery shopping in the morning","audioUrl":null},{"id":"a900ec8c-0f0b-482a-a154-026ff5aa674c","order":1,"chinese":"他总是很累","pinyin":"tā zǒng shì hěn lèi","english":"He''s always tired","audioUrl":null},{"id":"fa811233-10f0-43cd-ae7d-d569889b9274","order":2,"chinese":"你收拾房间总是不够干净，还是那么脏","pinyin":"nǐ shōu shí fáng jiān zǒng shì bú gòu gān jìng hái shì nà me zāng","english":"You never clean your room well enough — it''s still so dirty","audioUrl":null},{"id":"17e49bbb-e6e7-40d5-a571-0d9649790b56","order":3,"chinese":"妈妈总是很担心我, 所以我才会向她说谎","pinyin":"mā ma zǒng shì hěn dān xīn wǒ suǒ yǐ wǒ cái huì xiàng tā shuō huǎng","english":"Mom always worries about me, which is why I lie to her","audioUrl":null},{"id":"d6c87f73-b049-4190-9e5b-5e0bfcadbaa5","order":4,"chinese":"我的儿子总是很积极参加课外活动","pinyin":"wǒ de ér zǐ zǒng shì hěn jī jí cān jiā kè wài huó dòng","english":"My son is always eager to take part in extracurricular activities","audioUrl":null},{"id":"8310fac4-b735-4f60-b605-dbab3fec523d","order":5,"chinese":"你一直骗你女朋友, 她还没发现吗","pinyin":"nǐ yī zhí piàn nǐ nǚ péng yǒu tā hái méi fā xiàn mā","english":"You keep lying to your girlfriend — hasn''t she noticed yet?","audioUrl":null},{"id":"b7c8525b-c447-40d1-b7b2-edf4193d4e0e","order":6,"chinese":"他一直不喜欢阿荣, 总是一见面就打架","pinyin":"tā yì zhí bù xǐ huān ā róng zǒng shì yí jiàn miàn jiù dǎ jià","english":"He''s never liked A-Rong; they fight every time they meet","audioUrl":null},{"id":"332683a6-c6ef-45b7-9120-092f78bceaf4","order":7,"chinese":"最近上班一直很不开心, 很想换工作","pinyin":"zuì jìn shàng bān yì zhí hěn bù kāi xīn hěn xiǎng huàn gōng zuò","english":"Work has been really unpleasant lately; I really want to change jobs","audioUrl":null},{"id":"987a788f-7948-40bc-b30d-c72c745dd769","order":8,"chinese":"她穿得很少, 结果就感冒了","pinyin":"tā chuān de hěn shǎo jié guǒ jiù gǎn mào le","english":"She wore too little, and ended up catching a cold","audioUrl":null},{"id":"01259ede-bebd-4fae-8a51-ef50275c4399","order":9,"chinese":"猫咪太可爱了, 结果忍不住把它带回家了","pinyin":"māo mī tài kě ài le jié guǒ rěn bu zhù bǎ tā dài huí jiā le","english":"The kitten was so cute that I couldn''t help but take it home","audioUrl":null},{"id":"bf85a0f1-0947-4338-b207-1dde163838cb","order":10,"chinese":"我已经练了很久, 结果表演的时候还是失手了","pinyin":"wǒ yǐ jīng liàn le hěn jǐu jié guǒ biǎo yǎn de shí hòu hái shì shī shǒu le","english":"I''d practiced for a long time, but still slipped up during the performance","audioUrl":null},{"id":"84ad0e92-18a7-45c2-a750-98efcca718ef","order":11,"chinese":"他明明早了起床, 结果还是来不及","pinyin":"tā míng míng zǎo le qǐ chuáng jié guǒ hái shì lái bù jí","english":"He clearly got up early, but still didn''t make it in time","audioUrl":null},{"id":"f18dbd79-b6f4-4225-ab45-b40296fb6fe5","order":12,"chinese":"你吃这么多巧克力结果就蛀牙了","pinyin":"nǐ chī zhè me duō qiǎo kè lì jié guǒ jiù zhù yá le","english":"You ate so much chocolate that you ended up with cavities","audioUrl":null},{"id":"3b49c6b4-2e58-47b5-b232-42d75b96ca16","order":13,"chinese":"爸爸最近总是乱发脾气","pinyin":"bà ba zuì jìn zǒng shì luàn fā pí qì","english":"Dad has been losing his temper for no reason lately","audioUrl":null},{"id":"4d8f90db-8dd5-44d4-a52a-2a38b52086b2","order":14,"chinese":"我一直适应不了大学生活","pinyin":"wǒ yì zhí shì yìng bù liǎo dà xué shēng huó","english":"I just can''t get used to university life","audioUrl":null}]}'::jsonb),
  (8, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"14f2952d-c9bd-4720-9785-33970ae7771f","order":0,"chinese":"你从来都很小心, 为什么会从树上掉下来?","pinyin":"nǐ cóng lái dōu hěn xiǎo xīn wèi shén me huì cóng shù shàng diào xià lái","english":"You''ve always been careful — how did you fall out of the tree?","audioUrl":null},{"id":"7edaa364-28d2-4ff1-be3c-ef5bea740480","order":1,"chinese":"我对你男朋友从来印象都很差","pinyin":"wǒ duì nǐ nán péng yǒu cóng lái yìn xiàng dōu hěn chà","english":"I''ve always had a bad impression of your boyfriend","audioUrl":null},{"id":"3c270f2b-d962-42ca-b387-1cbf82fa0ef1","order":2,"chinese":"我从来没有答应过要帮你这个忙","pinyin":"wǒ cóng lái méi yǒu dā yìng guò yào bāng nǐ zhè gè máng","english":"I never agreed to do you this favor","audioUrl":null},{"id":"36e3947f-8fe6-4d41-b2a2-df35b6ee7ede","order":3,"chinese":"你从来没有重视过我","pinyin":"nǐ cóng lái méi yǒu zhòng shì guò wǒ","english":"You''ve never taken me seriously","audioUrl":null},{"id":"c46312f0-f719-45e8-b93f-d45e93b195c6","order":4,"chinese":"我爸爸从来没有给过我压力","pinyin":"wǒ bà ba cóng lái méi yǒu gěi guò wǒ yā lì","english":"My dad has never put any pressure on me","audioUrl":null},{"id":"db641b0b-b296-4849-87a9-959953dce519","order":5,"chinese":"干嘛这么激动? 难道真的是你做的吗?","pinyin":"gān ma zhè me jī dòng nán dào zhēn de shì nǐ zuò de ma","english":"Why so worked up? Could it really have been you who did it?","audioUrl":null},{"id":"fb7e1078-68e1-4ff7-8462-df7aba30630a","order":6,"chinese":"他今天心情这么好, 难道加薪了?","pinyin":"tā jīn tiān xīn qíng zhè me hǎo nán dào jiā xīn le","english":"He''s in such a good mood today — could he have gotten a raise?","audioUrl":null},{"id":"b9183f49-36fb-41b9-9a12-b7f82fb58cb7","order":7,"chinese":"难道他是故意这么做的吗?","pinyin":"nán dào tā shì gù yì zhè me zuò de ma","english":"Could he have done it on purpose?","audioUrl":null},{"id":"a9f231b2-c5db-4935-931b-ee3e5f40a426","order":8,"chinese":"他从来很喜欢弹钢琴","pinyin":"tā cóng lái hěn xǐ huān tán gāng qín","english":"He''s always loved playing the piano","audioUrl":null},{"id":"d42159a9-39e6-480d-a3d1-a458efe25ae3","order":9,"chinese":"我从来没想过要当警察","pinyin":"wǒ cóng lái méi xiǎng guò yào dāng jīng chá","english":"I''ve never thought about becoming a police officer","audioUrl":null},{"id":"ea035d7c-4df2-439b-935e-b6ae535d0665","order":10,"chinese":"难道她知道我喜欢她","pinyin":"nán dào tā zhī dào wǒ xǐ huān tā","english":"Could it be that she knows I like her?","audioUrl":null}]}'::jsonb),
  (9, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"65188ea2-7e73-403d-8451-c5e0cdf1275c","order":0,"chinese":"直到十二点半, 我才做完功课","pinyin":"zhí dào shí èr diǎn bàn wǒ cái zuò wán gōng kè","english":"I didn''t finish my homework until half past twelve","audioUrl":null},{"id":"aedc550f-f18e-47ad-956f-99118b1fb635","order":1,"chinese":"我养了这只猫三个月, 直到昨天牠才让我摸","pinyin":"wǒ yǎng liǎo zhè zhī māo sān gè yuè zhí dào zuó tiān tā cái ràng wǒ mō","english":"I''ve had this cat for three months, and only yesterday did it let me pet it","audioUrl":null},{"id":"ce652492-2e3e-4fcf-88df-357627b5e1b6","order":2,"chinese":"直到我的头发越来越长, 我才决定去剪头发","pinyin":"zhí dào wǒ de tóu fa yuè lái yuè cháng wǒ cái jué dìng qù jiǎn tóu fa","english":"It wasn''t until my hair got longer and longer that I decided to get a haircut","audioUrl":null},{"id":"09d975a0-8856-4bd4-8313-15ba8133bb7a","order":3,"chinese":"在两个月内, 她学了一个新语言","pinyin":"zài liǎng gè yuè nèi tā xué le yí gè xīn yǔ yán","english":"Within two months, she learned a new language","audioUrl":null},{"id":"304195b2-b305-4172-ae19-59a3293955ce","order":4,"chinese":"在这半年内, 我的食量比平时多了一倍","pinyin":"zài zhè bàn nián nèi wǒ de shí liàng bǐ píng shí duō le yí bèi","english":"Within this half year, my appetite has doubled compared to usual","audioUrl":null},{"id":"19d3a637-ae78-4096-a05d-eee3ddc404f5","order":5,"chinese":"我在三个小时内已经看完这本书的内容","pinyin":"wǒ zài sān gè xiǎo shí nèi yǐ jīng kàn wán zhè běn shū de nèi róng","english":"Within three hours, I''d already finished reading this book","audioUrl":null},{"id":"12ddb82a-f73d-4eba-b292-37257f40ca96","order":6,"chinese":"看来自从他买了这款新游戏以来就没吃过饭","pinyin":"kàn lái zì cóng tā mǎi le zhè kuǎn xīn yóu xì yǐ lái jiù méi chī guò fàn","english":"It seems he hasn''t eaten since he bought this new game","audioUrl":null},{"id":"8e56a514-cb7b-4021-8f42-96b3ac49f500","order":7,"chinese":"一直以来她都是所有同学当中看起来最开心的","pinyin":"yì zhí yǐ lái tā dōu shì suǒ yǒu tóng xué dāng zhōng kàn qǐ lái zuì kāi xīn de","english":"She''s always seemed the happiest of all the classmates","audioUrl":null},{"id":"f2645526-695d-4452-b7b8-11c36a0c4d12","order":8,"chinese":"三年以来我跟他都没说过话","pinyin":"sān nián yǐ lái wǒ gēn tā dōu méi shuō guò huà","english":"In three years, he and I haven''t spoken","audioUrl":null},{"id":"d952c699-22f6-4264-a718-bf7743092c33","order":9,"chinese":"他在一年内考了三次驾照","pinyin":"tā zài yì nián nèi kǎo le sān cì jià zhào","english":"He took the driving test three times within a year","audioUrl":null},{"id":"c5665095-a72e-453a-9780-cc5c1c3659a7","order":10,"chinese":"直到闹钟响了五次我才醒来","pinyin":"zhí dào nào zhōng xiǎng le wǔ cì wǒ cái xǐng lái","english":"I didn''t wake up until the alarm had gone off five times","audioUrl":null}]}'::jsonb),
  (10, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"bdf3db03-f741-4cbb-8ea9-472aca94576e","order":0,"chinese":"你果然吃了四分之一个蛋糕","pinyin":"nǐ guǒ rán chī le sì fēn zhī yī gè dàn gāo","english":"Sure enough, you ate a quarter of the cake","audioUrl":null},{"id":"0f0c21b3-83ed-4acf-b818-55140a943270","order":1,"chinese":"这个人显然不值得你为他这么做","pinyin":"zhè gè rén xiǎn rán bù zhí dé nǐ wèi tā zhè me zuò","english":"This person clearly isn''t worth you doing this for him","audioUrl":null},{"id":"fe81bb76-514d-47cd-95f6-9d7c5b278285","order":2,"chinese":"既然你去逛街, 不如帮我买点东西","pinyin":"jì rán nǐ qù guàng jiē bù rú bāng wǒ mǎi diǎn dōng xi","english":"Since you''re going shopping, why not pick up a few things for me?","audioUrl":null},{"id":"9e2542c7-f7ba-4e43-89ef-996d9d5351e4","order":3,"chinese":"虽然我们不熟, 但遇到暴风雪我们都会互助","pinyin":"suī rán wǒ men bù shú dàn yù dào bào fēng xuě wǒ men dōu huì hù zhù","english":"Although we''re not close, in a blizzard we''d still help each other","audioUrl":null},{"id":"9d2c84d1-6fff-4a04-acb5-e35b90fa4acf","order":4,"chinese":"他这么做实在是不对, 而且还不愿意道歉","pinyin":"tā zhè me zuò shí zài shì bú duì ér qiě hái bú yuàn yì dào qiàn","english":"What he did is really wrong, and on top of that he won''t apologize","audioUrl":null},{"id":"dbdc6b85-41c8-4dc5-ab48-bf9ef13b8467","order":5,"chinese":"事实上他一点也不严肃, 反而很喜欢说笑话","pinyin":"shì shí shàng tā yī diǎn yě bù yán sù fǎn ér hěn xǐ huān shuō xiào huà","english":"In fact, he''s not serious at all — on the contrary, he loves telling jokes","audioUrl":null},{"id":"40195886-b7b2-4de1-9e42-6d318a9c9641","order":6,"chinese":"你以前总是说不结婚反而最早结婚是你","pinyin":"nǐ yǐ qián zǒng shì shuō bù jié hūn fǎn ér zuì zǎo jié hūn shì nǐ","english":"You always used to say you''d never marry, yet you were the first to get married","audioUrl":null},{"id":"83bbb064-be35-4fe3-8466-881633ff70c6","order":7,"chinese":"虽然他长大了很多, 然而还是很活泼","pinyin":"suī rán tā zhǎng dà le hěn duō rán ér hái shì hěn huó pō","english":"Although he''s grown up a lot, he''s still very lively","audioUrl":null},{"id":"09f6e93c-3f3b-43fb-9f6e-282fe6b0bed4","order":8,"chinese":"不是我不想给你打电话, 而是我手机没电了","pinyin":"bú shì wǒ bù xiǎng gěi nǐ dǎ diàn huà ér shì wǒ shǒu jī méi diàn le","english":"It''s not that I didn''t want to call you — it''s that my phone died","audioUrl":null}]}'::jsonb),
  (11, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"7d73ea2a-591a-46b7-b9c5-c3c2498a0aa3","order":0,"chinese":"我拿着很多东西, 有西红柿, 鸡蛋, 面包等等","pinyin":"wǒ ná zhe hěn duō dōng xi yǒu xī hóng shì jī dàn miàn bāo děng děng","english":"I''m carrying a lot of things — tomatoes, eggs, bread, and so on","audioUrl":null},{"id":"56ef5132-8ae5-48ee-b560-fe5b7906df34","order":1,"chinese":"我看着你把房间弄乱的","pinyin":"wǒ kàn zhe nǐ bǎ fáng jiān nòng luàn de","english":"I watched you mess up the room","audioUrl":null},{"id":"e71e8e04-16fd-4e32-b5df-116b76882a54","order":2,"chinese":"不要戴着耳机跟人打招呼","pinyin":"bú yào dài zhe ěr jī gēn rén dǎ zhāo hū","english":"Don''t greet people while wearing headphones","audioUrl":null},{"id":"d53ca4c9-2283-411d-a42f-00caa9e90834","order":3,"chinese":"不要坐着拉小提琴, 站起来","pinyin":"bú yào zuò zhe lā xiǎo tí qín zhàn qǐ lái","english":"Don''t play the violin sitting down — stand up","audioUrl":null},{"id":"9a2ead24-3a92-4c04-b692-83be95baa003","order":4,"chinese":"看着前面开车, 不要边看手机边开","pinyin":"kàn zhe qián miàn kāi chē bú yào biān kàn shǒu jī biān kāi","english":"Keep your eyes ahead while driving — don''t drive while looking at your phone","audioUrl":null},{"id":"53bae23b-bc23-4f81-8fc3-274e61280ca2","order":5,"chinese":"我推着手推车在走出来","pinyin":"wǒ tuī zhe shǒu tuī chē zài zǒu chū lái","english":"I''m walking out pushing a cart","audioUrl":null},{"id":"18cf7fea-3cc7-4421-b130-505a60285ffe","order":6,"chinese":"你暂时帮我拿着包包","pinyin":"nǐ zàn shí bāng wǒ ná zhe bāo bāo","english":"Hold my bag for me for a moment","audioUrl":null},{"id":"12d5f53d-d56f-4333-acce-670403db9c98","order":7,"chinese":"我忙着切火锅的材料","pinyin":"wǒ máng zhe qiē huǒ guō dí cái liào","english":"I''m busy cutting the ingredients for the hot pot","audioUrl":null}]}'::jsonb),
  (12, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"b137db74-1282-4c0a-bd3b-cc015700a276","order":0,"chinese":"我怀疑是你吃掉了我的薯片","pinyin":"wǒ huái yí shì nǐ chī diào le wǒ de shǔ piàn","english":"I suspect it was you who ate my potato chips","audioUrl":null},{"id":"5d1bb23a-544d-41eb-bd19-b674c4cffb15","order":1,"chinese":"你表演完之后记得跟我们拍照","pinyin":"nǐ biǎo yǎn wán zhī hòu jì de gēn wǒ men pāi zhào","english":"After your performance, remember to take a photo with us","audioUrl":null},{"id":"5a400f4c-6a54-48c4-9339-ebc295390c81","order":2,"chinese":"在家吃火锅尽量把窗户打开","pinyin":"zài jiā chī huǒ guō jǐn liàng bǎ chuāng hù dǎ kāi","english":"When you eat hot pot at home, try to keep the windows open","audioUrl":null},{"id":"b7c5bb56-9cdc-4f32-9e09-b3532afad821","order":3,"chinese":"你还没戴眼镜, 看得清楚吗","pinyin":"nǐ hái méi dài yǎn jìng kàn de qīng chǔ ma","english":"You haven''t put on your glasses yet — can you see clearly?","audioUrl":null},{"id":"88ef0da5-625a-4561-aabe-4fd664db4d07","order":4,"chinese":"我已经表达的很清楚","pinyin":"wǒ yǐ jīng biǎo dá de hěn qīng chǔ","english":"I''ve already expressed it very clearly","audioUrl":null},{"id":"1254c613-93ce-4ef9-9a51-082411e7444a","order":5,"chinese":"飞机因为气流的关系降落不了","pinyin":"fēi jī yīn wèi qì liú de guān xi jiàng luò bù liǎo","english":"The plane can''t land because of the turbulence","audioUrl":null},{"id":"cdfbc9ba-f12c-4122-bf2c-41a1a7ac21f3","order":6,"chinese":"教授说完之后我还是听不懂","pinyin":"jiào shòu shuō wán zhī hòu wǒ hái shì tīng bù dǒng","english":"Even after the professor finished, I still didn''t understand","audioUrl":null},{"id":"06857db4-f073-4212-8b29-88020fa2e92e","order":7,"chinese":"把饼干碎捡起来","pinyin":"bǎ bǐng gān suì jiǎn qǐ lái","english":"Pick up the cookie crumbs","audioUrl":null},{"id":"e91d92b0-b393-4b34-80dd-1474eec424ef","order":8,"chinese":"不要随便在高速公路把车停下","pinyin":"bú yào suí biàn zài gāo sù gōng lù bǎ chē tíng xià","english":"Don''t just stop your car on the highway","audioUrl":null},{"id":"cd2372de-00bd-4d70-ba5c-a5aa93602c2b","order":9,"chinese":"这瓶香水闻起来很像棉花糖","pinyin":"zhè píng xiāng shuǐ wén qǐ lái hěn xiàng mián huā táng","english":"This perfume smells a lot like cotton candy","audioUrl":null},{"id":"744158d4-8bf4-4db0-950a-6136459dea3e","order":10,"chinese":"你的菜做得很好","pinyin":"nǐ de cài zuò de hěn hǎo","english":"You cook really well","audioUrl":null},{"id":"9ce7686c-70c9-4c72-b051-25c665736e70","order":11,"chinese":"我快被你烦死了","pinyin":"wǒ kuài bèi nǐ fán sǐ le","english":"You''re driving me crazy","audioUrl":null},{"id":"7c445974-3fca-4faf-984e-5658c4bd46cd","order":12,"chinese":"我说了两次","pinyin":"wǒ shuō le liǎng cì","english":"I said it twice","audioUrl":null},{"id":"f4a57c8a-e6ce-48b2-94e1-a98b48ec623c","order":13,"chinese":"我已经说过无数次不要这么晚回家","pinyin":"wǒ yǐ jīng shuō guò wú shù cì bú yào zhè me wǎn huí jiā","english":"I''ve told you countless times not to come home so late","audioUrl":null},{"id":"d3167296-e25a-4182-9ce8-31ae2e631f6b","order":14,"chinese":"万里长城我已经来过几遍了","pinyin":"wàn lǐ cháng chéng wǒ yǐ jīng lái guò jǐ biàn le","english":"I''ve been to the Great Wall several times already","audioUrl":null},{"id":"a7bbbdc8-21c8-4009-afb4-146ddcb36da6","order":15,"chinese":"我要去一趟超级市场","pinyin":"wǒ yào qù yí tàng chāo jí shì chǎng","english":"I need to make a trip to the supermarket","audioUrl":null},{"id":"862c3060-e74a-43d2-a33b-77435b8b4841","order":16,"chinese":"我等你回来等到天亮","pinyin":"wǒ děng nǐ huí lái děng dào tiān liàng","english":"I waited for you to come back until dawn","audioUrl":null},{"id":"fdd0a215-67ec-4131-8a32-9c76bfd4b717","order":17,"chinese":"这视频我看到第十秒已经不想看","pinyin":"zhè shì pín wǒ kàn dào dì shí miǎo yǐ jīng bù xiǎng kàn","english":"By the tenth second of this video I already didn''t want to keep watching","audioUrl":null},{"id":"615d3270-62a8-42e8-a2de-a4fc710845ac","order":18,"chinese":"你一次用掉了半瓶洗发水","pinyin":"nǐ yī cì yòng diào le bàn píng xǐ fà shuǐ","english":"You used up half a bottle of shampoo at once","audioUrl":null},{"id":"34aed437-59ec-491a-9c32-2a69b6068d7a","order":19,"chinese":"这个广告我已经看过十遍","pinyin":"zhè ge guǎng gào wǒ yǐ jīng kàn guò shí biàn","english":"I''ve already seen this ad ten times","audioUrl":null},{"id":"953a204c-0075-4ad0-984a-3bdfeaed1774","order":20,"chinese":"导游站在前面介绍景点","pinyin":"dǎo yóu zhàn zài qián miàn jiè shào jǐng diǎn","english":"The tour guide stands at the front introducing the sights","audioUrl":null}]}'::jsonb),
  (13, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"811508dd-b6fb-4536-8031-9e15c58b2d62","order":0,"chinese":"我很喜欢这本书的作者","pinyin":"wǒ hěn xǐ huān zhè běn shū de zuò zhě","english":"I really like the author of this book","audioUrl":null},{"id":"d035b320-dd80-44ce-a4c5-3c3a4d271683","order":1,"chinese":"粗心的弟弟总是忘了带手机","pinyin":"cū xīn de dì di zǒng shì wàng le dài shǒu jī","english":"My careless little brother always forgets to bring his phone","audioUrl":null},{"id":"00f5f74a-58d0-467f-af54-5e8766543e5b","order":2,"chinese":"妈妈做了很丰富的晚餐","pinyin":"mā ma zuò le hěn fēng fù de wǎn cān","english":"Mom made a hearty dinner","audioUrl":null},{"id":"35e3000f-137f-4995-9740-a62653f471d4","order":3,"chinese":"你得记住我给你的建议","pinyin":"nǐ děi jì zhù wǒ gěi nǐ de jiàn yì","english":"You have to remember the advice I gave you","audioUrl":null},{"id":"7689b825-b0e8-451d-bb20-e8a557401c2f","order":4,"chinese":"下次遇到这种情况你得懂得拒绝人","pinyin":"xià cì yù dào zhè zhǒng qíng kuàng nǐ děi dǒng de jù jué rén","english":"Next time you''re in this situation, you have to know how to say no","audioUrl":null},{"id":"ea5906ca-14d2-438d-865e-af278f590841","order":5,"chinese":"你得看清楚合约内容","pinyin":"nǐ děi kàn qīng chǔ hé yuē nèi róng","english":"You have to read the contract carefully","audioUrl":null},{"id":"2f76f8b8-e44a-4abc-a72e-0a0a52feb83a","order":6,"chinese":"我很努力才获得这个硕士学位","pinyin":"wǒ hěn nǔ lì cái huò dé zhè gè shuò shì xué wèi","english":"I worked hard to earn this master''s degree","audioUrl":null},{"id":"d7f6fede-2329-40ed-83ec-777200b428ee","order":7,"chinese":"最终我们顺利赢得冠军","pinyin":"zuì zhōng wǒ men shùn lì yíng de guàn jūn","english":"In the end, we won the championship smoothly","audioUrl":null},{"id":"3ea24182-2979-456f-982b-96bffb48babe","order":8,"chinese":"得到这个消息之后我很烦恼","pinyin":"dé dào zhè gè xiāo xi zhī hòu wǒ hěn fán nǎo","english":"After getting this news, I felt really troubled","audioUrl":null},{"id":"d917bda9-3a53-4c97-968f-4c38109786cf","order":9,"chinese":"他很兴奋地跳了起来","pinyin":"tā hěn xīng fèn de tiào le qǐ lái","english":"He jumped up excitedly","audioUrl":null},{"id":"c3c10541-0292-420f-bbc4-f3de60846895","order":10,"chinese":"妈妈不断地鼓励我","pinyin":"mā ma bú duàn de gǔ lì wǒ","english":"Mom encourages me constantly","audioUrl":null},{"id":"b50c7d1e-1da4-4a50-aa2e-91e275319d6c","order":11,"chinese":"我们班激动地讨论学校旅行要去哪","pinyin":"wǒ mén bān jī dòng de tǎo lùn xué xiào lǚ xíng yào qù nǎ","english":"Our class excitedly discussed where to go for the school trip","audioUrl":null},{"id":"42e94a46-6381-4cda-9b65-b461b21baed2","order":12,"chinese":"你的优点就是很幽默","pinyin":"nǐ de yōu diǎn jiù shì hěn yōu mò","english":"Your strength is that you''re very funny","audioUrl":null},{"id":"d3be8860-b9bf-47ed-898a-b330299adb65","order":13,"chinese":"这个意外你得负责任","pinyin":"zhè ge yì wài nǐ děi fù zé rèn","english":"You have to take responsibility for this accident","audioUrl":null},{"id":"29c38fc9-d4f2-4713-9333-a430b6785165","order":14,"chinese":"我很轻松地面对这个难关","pinyin":"wǒ hěn qīng sōng de miàn duì zhè gè nán guān","english":"I faced this difficulty with ease","audioUrl":null}]}'::jsonb)
) AS v(n, content)
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."title" ILIKE '%intensive listening%'
  AND (substring(lower(l."title") from 'advanced[^0-9]*([0-9]+)'))::int = v.n
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
  );
